// src/pages/Projects.jsx
// Shows all projects, allows admin to create new ones

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Projects = () => {
  const [projects, setProjects] = useState([]);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [error, setError] = useState('');
  const { user } = useAuth();
  const navigate = useNavigate();

  // Load projects when page opens
  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const { data } = await API.get('/projects');
      setProjects(data.projects);
    } catch (err) {
      setError('Failed to load projects');
    }
  };

  const handleCreate = async () => {
    if (!name) return setError('Project name is required');
    try {
      await API.post('/projects', { name, description });
      setName('');
      setDescription('');
      fetchProjects(); // Refresh list
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create project');
    }
  };

  return (
    <div style={styles.container}>
      <h2>📁 Projects</h2>

      {/* Admin only: Create project form */}
      {user?.role === 'admin' && (
        <div style={styles.form}>
          <h3>Create New Project</h3>
          {error && <div style={styles.error}>{error}</div>}
          <input style={styles.input} placeholder="Project Name"
            value={name} onChange={(e) => setName(e.target.value)} />
          <input style={styles.input} placeholder="Description (optional)"
            value={description} onChange={(e) => setDescription(e.target.value)} />
          <button style={styles.button} onClick={handleCreate}>
            + Create Project
          </button>
        </div>
      )}

      {/* Projects list */}
      <div style={styles.grid}>
        {projects.map((project) => (
          <div key={project._id} style={styles.card}
            onClick={() => navigate(`/projects/${project._id}/tasks`)}>
            <h3 style={styles.cardTitle}>{project.name}</h3>
            <p style={styles.cardDesc}>{project.description || 'No description'}</p>
            <div style={styles.badge}>{project.status}</div>
            <p style={styles.members}>
              👥 {project.members?.length || 0} members
            </p>
            <p style={styles.viewLink}>View Tasks →</p>
          </div>
        ))}
      </div>

      {projects.length === 0 && (
        <p style={{ color: '#94a3b8' }}>No projects yet. Create one above!</p>
      )}
    </div>
  );
};

const styles = {
  container: { maxWidth: '900px', margin: '0 auto' },
  form: {
    background: 'white', padding: '24px', borderRadius: '12px',
    boxShadow: '0 2px 10px rgba(0,0,0,0.08)', marginBottom: '24px',
    display: 'flex', flexDirection: 'column', gap: '12px',
  },
  input: { padding: '10px', border: '1px solid #e2e8f0', borderRadius: '8px', fontSize: '14px' },
  button: { backgroundColor: '#3b82f6', color: 'white', border: 'none', padding: '10px', borderRadius: '8px', cursor: 'pointer' },
  error: { background: '#fee2e2', color: '#dc2626', padding: '10px', borderRadius: '6px' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '16px' },
  card: {
    background: 'white', padding: '20px', borderRadius: '12px',
    boxShadow: '0 2px 10px rgba(0,0,0,0.08)', cursor: 'pointer',
    transition: 'transform 0.2s', border: '1px solid #f1f5f9',
  },
  cardTitle: { margin: '0 0 8px', color: '#1e293b' },
  cardDesc: { color: '#64748b', fontSize: '14px', margin: '0 0 12px' },
  badge: {
    display: 'inline-block', background: '#dbeafe', color: '#1d4ed8',
    padding: '2px 10px', borderRadius: '20px', fontSize: '12px',
  },
  members: { color: '#94a3b8', fontSize: '13px', margin: '8px 0 0' },
  viewLink: { color: '#3b82f6', fontSize: '13px', margin: '4px 0 0' },
};

export default Projects;
